var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"좋은 아침입니다, 아카데미 학생 여러분.","JPN":"おはようございます、アカデミー生徒の皆さん。","ENG":"Good morning, Academy students.","TWN":"學院的同學們，大家早安。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"다들 아시겠지만, 아카데미는 학생들의 풍부한 경험과 바른 인성 함양을 위해 정기적으로 외부인사 초청회를 열고 있어요.","JPN":"ご存じのとおり、アカデミーは生徒に豊富な経験を提供し、人格者として成長できる道を提示するべく、定期的に招聘講演会を開いています。","ENG":"As you know, our school regularly invites guest speakers to help us broaden our experience and develop good character.","TWN":"大家應該都知道，為了培養學生有豐富的見識，以及好的品格，學院會定期邀請校外人士來分享。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그 중에서도 오늘은 특별한 분을 모시게 됐습니다.","JPN":"そして本日はとても特別な方をお招きしました。","ENG":"And today, it's invited a very special guest.","TWN":"我們今天就請到一位特別來賓。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"태스크포스, <color=#ffd34c>조디악 나이츠</color>. 피오네 로웰 부단장님이십니다.","JPN":"タスクフォース、<color=#ffd34c>ゾディアックナイツ</color>。フィオネ・ローウェル副団長です。","ENG":"It's Deputy Fione Rowell of the <color=#ffd34c>Zodiac Knights</color> TASKFORCE.","TWN":"就是特遣勢力 <color=#ffd34c>十二宮騎士團</color>的菲奧尼副團長。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"모두 박수로 맞아주시길.","JPN":"拍手でお迎えください。","ENG":"Let's welcome her with a round of applause!","TWN":"掌聲歡迎她～"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"……조디악 나이츠?","JPN":"……ゾディアックナイツ？","ENG":"...The Zodiac Knights?","TWN":"……十二宮騎士團？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"기사 코스프레로 유명한 태스크포스 아니야?","JPN":"騎士のコスプレで有名なタスクフォースじゃないか？","ENG":"The TASKFORCE known for its knight costumes?","TWN":"不就是那個Cosplay騎士很出名的特遣勢力嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"맞아, 맞아. 그 민중을 지키는 기사단!","JPN":"そうそう、あの民衆を守る騎士団！","ENG":"Yes, yes. The knights who serve the public!","TWN":"對啊對啊。就是那個守護民眾的騎士團！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"……푸핫, 민중을 지킨다니. 그게 뭐야? 무슨 촌스러운 옛날 만화도 아니고.","JPN":"……ぷはっ！　民衆を守るとかダサすぎる。昔の漫画じゃあるまいし。","ENG":"...Pssh! Serve the public. What does that mean? Sounds like some old, corny cartoon catchphrase.","TWN":"……噗哈哈，還守護民眾咧？什麼鬼？又不是很久以前的漫畫！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"안녕하십니까, 아카데미 학생 여러분.","JPN":"おはようございます、アカデミー生徒の皆さん。","ENG":"Good morning, students of the Academy.","TWN":"學院的同學們，大家好。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"조디악 나이츠의 부단장 직위를 맏고 있는 피오네 로웰이라고 합니다.","JPN":"ゾディアックナイツの副団長を勤めています、フィオネ・ローウェルと申します。","ENG":"My name is Fione Lowell, and I'm the deputy captain of the Zodiac Knights.","TWN":"我是十二宮騎士團的副團長，菲奧尼。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아카데미 학생 여러분의 명성은 익히 들어 잘 알고 있습니다.","JPN":"アカデミーの皆さんの素晴らしさについては、私もよく話を聞いています。","ENG":"I've heard many great things about you and your school.","TWN":"久仰各位同學的大名。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"오늘 하루, 여러분의 일일 교관으로 초청 받아 무척 기쁘게 생각하고 있습니다.","JPN":"今日は皆さんの1日教官としてお招きいただき、とても嬉しく思っています。","ENG":"I'm honored to be here as your instructor for the day.","TWN":"非常開心能夠受邀擔任各位同學的一日教官。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그러니 모쪼록…….","JPN":"本日は何卒……","ENG":"And hopefully...","TWN":"那就請多……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐야? 기사 흉내나 내는 관종 집단이 누굴 가르친다는 거야?","JPN":"は？　騎士気取りの集団のくせに私たちを指導するとか、図々しいんじゃない？","ENG":"What? No, I've got nothing to learn from some pseudo knight group.","TWN":"什麼嘛？不過就是靠模仿騎士賺讚數的組織，竟然說要當我們的教官？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나이엘! 말이 너무 심하잖아!","JPN":"ナイエル！　さすがにそれは言い過ぎだよ！","ENG":"Naielle! That's not nice!","TWN":"奈爾！你這樣說太過分了！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"흥! 학생회에서도 예산을 너무 쪼잔하게 쓰는 거 아니야?","JPN":"ふんっ！　生徒会も予算ケチりすぎよ。","ENG":"Geez, is the Student Council budget so low?","TWN":"哼！學生會也太節省預算了吧？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"얼마나 초청할 사람이 없었으면, 저런 촌스러운 냄새 풍기는 구닥다리를 초대한 거냐구.","JPN":"いくら人材がいないからって、あんなダサい人を呼ぶなんてありえない。","ENG":"Of all the people they could have invited, they invited that—an old, unsophisticated-looking country woman.","TWN":"是沒人可以邀請了嗎？竟然請到這種土裡土氣的傢伙！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"적어도 이 나이엘 님이 보고 감탄할 만큼 대단한 사람을 모셔 와야지.","JPN":"せめてこのナイエル様が尊敬できるようなすごい人を呼んでちょうだいよね。","ENG":"Why can't they bring in someone who can impress me?","TWN":"起碼也邀請個讓我看一眼就能發出讚嘆的人物吧！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐, 애초에 그런 사람이 얼마나 있겠냐만은.","JPN":"まあ、そんな人そうそういないでしょうけど。","ENG":"But then again, it's an impossible task to accomplish.","TWN":"雖然這種人是不多啦！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나이엘, 네가 몰라서 그렇지 사실, 조디악 나이츠는…….","JPN":"ナイエルが知らないだけで、実はゾディアックナイツって……","ENG":"Naielle, you don't know what you're talking about. The Zodiac Knights—","TWN":"奈爾，應該是你孤陋寡聞，其實十二宮騎士團……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"거기, 양갈래 머리 여학생?","JPN":"そこのツインテールの女子生徒さん？","ENG":"Excuse me, you with the pigtails.","TWN":"我說，雙馬尾同學？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"……뭐, 뭐어? 양갈래 머리?","JPN":"……つ、ツインテール？","ENG":"...Wh-what? Pigtails?","TWN":"……什…什麼？雙馬尾？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"기사를 앞에 두고도 전혀 주눅들지 않는 태도 아주 보기 좋군요.","JPN":"騎士を前にしても全く怯まないその態度、素晴らしいです。","ENG":"I like your spunkiness. You refuse to be intimidated by the knight in front of you.","TWN":"我很欣賞你在騎士面前也無所畏懼的態度。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"양갈래 머리 학생의 실력은 잠시 뒤 2교시에 있을 실습시간에 구경하도록 하겠습니다.","JPN":"ツインテールさんの腕は、2限目の実技授業でとくと見させてもらいましょう。","ENG":"I can't wait to see what you can do during our next training class.","TWN":"至於雙馬尾同學的實力如何，我會在稍後的第二節實習課中確認。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"으, 으응?","JPN":"え、え？","ENG":"S-say what?","TWN":"呃…蛤？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"다만, 그전에 한 가지만큼은 정정하도록 하죠.","JPN":"ただその前に、1つだけ訂正します。","ENG":"But first, let me clarify this.","TWN":"不過，在那之前，我要更正一件事。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"우리 조디악 나이츠는 단순히 기사 흉내가 아닌, 오랜 세월동안 인류를 수호한 진짜 기사들입니다.","JPN":"私たちゾディアックナイツは単に騎士を気取ってるわけではなく、長きに渡って人類を守護している本物の騎士です。","ENG":"We Zodiac Knights aren't some pseudo knight group. We're real knights who've been protecting humanity for a long time.","TWN":"我們十二宮騎士團不是只會模仿騎士，我們是從過去到現在，一直不斷守護人類的真正騎士。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"물론 대중이 인식하고 있는 기사라는 단어와 그 실체 사이에서는 어느정도 간극이 있다는 것은 인정하지만……","JPN":"もちろん、大衆が認識している騎士の概念と、その実体に少し差があるという点は認めますが……","ENG":"Of course, we understand that there's a gap between us and the general notion of the knight…","TWN":"當然我承認大眾認知中的騎士，和現實是有落差的……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그럼에도 조디악 나이츠의 설립자이신 별의 인도자께서는 사람을 구하기 위해 열 두 가문을 규합하여 기사단을 설립하셨습니다.","JPN":"それでもゾディアックナイツの創立者である星の導き手は、人々を助けるために12家門を集め、騎士団を立ち上げました。","ENG":"But still, it doesn't change the fact that our founder, the Star Guide, rallied twelve families and established the Knights to save people.","TWN":"不過十二宮騎士團的創辦人 星之引導者，是基於守護人們的目的為前提，才會集結十二個家族創立騎士團的。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"참고로 저희 로웰 가문에서는 특별히 기사단의 신념을 올바르게 계승하기 위해……","JPN":"ちなみに、我がローウェル家では、騎士団の信念を正しく継承するために……","ENG":"Especially, the members of my family, Lowell, in order to uphold the convictions of the Knights—","TWN":"提供大家參考，我們勞威爾家族，堅持繼承正統的騎士團理念……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"……","TWN":"……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"……흠냐. 왜 이렇게 조용하지.","JPN":"……むにゃ……どうしてこんなに静かなんだろ……？","ENG":"*Smacks her lips...* Why is everyone so quiet?","TWN":"……哈啊～怎麼這麼安靜？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"벌써 점심 시간인가?","JPN":"もう昼休み……？","ENG":"Is it lunchtime already?","TWN":"已經到午餐時間了嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……그래서 이 이야기는 제가 훈련으로 인해 부상으로 잠시 조부님을 따라 오를레앙에 머물던 시절.","JPN":"……これは私が訓練で負傷し、しばらく祖父と一緒にオルレアンに滞在していた頃、","ENG":"...So, I heard this story while staying in Orleans with my grandfather after I got injured during training.","TWN":"……這個故事呢，是在我因為訓練受傷，暫時跟著祖父到奧爾良居住的時候，"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"고된 재활치료로 마음이 약해지던 그때, 조부께서 제게 들려주셨던 이야기입니다.","JPN":"リハビリの辛さに心が弱っていた私に、祖父が聞かせてくれた話です。","ENG":"He'd tell it to me to perk me up after my painful physical therapy.","TWN":"當時我因為辛苦的復健而意志消沈，祖父就說了這個故事給我聽。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"지금도 종종 떠올리곤 하죠. 그때 조부께서 저를 북돋아 주지 않으셨다면……","JPN":"今も時々思い出します。あの時祖父に励ましてもらえなかったら……","ENG":"I still think of that time sometimes. If he didn't encourage me at that time...","TWN":"到現在我還是會時常想起來呢，那時候若不是祖父鼓勵我……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"저는 이 자리에 떳떳하게 서 있을 수 없을지도 모른다는 걸요. 하지만 때때로……","JPN":"堂々とこの場に立つことすらできなくなっていたかもしれません。ですが……","ENG":"I might not be standing here so proudly in front of you. But sometimes...","TWN":"我現在可能也無法這麼有自信地站在你們面前。不過有時候……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"……쿠울.","JPN":"……ぐう。","ENG":"Zzz...","TWN":"……呼嚕。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"결과적으로, 저희 증조부께선 민중을 수호하시고…….","JPN":"結果的に、曽祖父は民衆を守り……","ENG":"In the end, my great grandfather protected the public...","TWN":"總而言之，我的曾祖父守護民眾……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"……흠흠.","JPN":"……コホン。","ENG":"...Ahem, ahem.","TWN":"……咳咳。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"오리엔테이션은 이쯤해도 충분하겠군요.","JPN":"オリエンテーションはこの辺で十分かと。","ENG":"I think we should conclude the orientation now.","TWN":"說明到這邊就差不多了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"다음 일정으로는 실습 훈련이 예정되어 있습니다.","JPN":"次のスケジュールは実技訓練です。","ENG":"The next thing on our schedule is a practical exercise.","TWN":"接下來是實習訓練的時間。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"창과 방패처럼 무거운 냉병기의 사용법을 전문적으로 배운 카운터는 흔치 않죠.","JPN":"槍や盾のように重い冷兵器の扱い方を専門としているカウンターはそうそういません。","ENG":"Not many Counters know how to professionally use heavy weapons, such as spears and shields.","TWN":"專門學習長槍和盾牌這類冷兵器的制裁者並不常見。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"피오네님께서 직접 지도해주실 테니 학생 여러분들에겐 좋은 경험이 될 겁니다.","JPN":"フィオネさんに直接指導していただく予定です。皆さんにもいい経験になるでしょう。","ENG":"Deputy Fione can teach us that. It'll be a good experience for all of us.","TWN":"菲奧尼會親自指導大家，相信對各位同學來說會是個很好的經驗。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……흐음.","JPN":"……ふむふむ。","ENG":"...Hm.","TWN":"……嗯嗯。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"케이시 빈즈 학생?","JPN":"ケイシー・ビンズさん？","ENG":"Kaci Bins.","TWN":"卡西·比恩茲同學？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"네, 넵!","JPN":"は、はいっ！","ENG":"Y-yes?","TWN":"是…是！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"이렇게 어린 나이에 할버드 같이 난이도 높은 무장을 사용하다니 대단하군요.","JPN":"まだ若いのに、ハルバードのような高難易度の武装を使いこなせるなんてすごいですね。","ENG":"You're young, but you already know how to wield a halberd with impressive skill. That's amazing.","TWN":"沒想到你小小年紀，就使用斧槍這種高難度的武器，真是厲害。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"고, 고맙습니다.","JPN":"あ、ありがとうございます。","ENG":"Th-thank you.","TWN":"謝…謝謝。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"무엇보다도 커다란 할버드를 다루는 근력과 균형 감각의 밸런스가 뛰어나요.","JPN":"特に、大きなハルバードを扱える程の筋力とバランス感覚が優れています。","ENG":"Most of all, it's incredible that such a tiny girl like you swings such a big weapon without losing balance.","TWN":"最重要的是，你操控斧槍的力量和平衡也都掌握得很好。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"혹시 어떤 훈련을 하고 있는지 여쭈어봐도 될까요?","JPN":"普段どんな訓練をしているか、聞かせてくれませんか？","ENG":"May I ask what kind of training you do?","TWN":"我能問問你平時都做些什麼訓練嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"……후, 훈련이요?","JPN":"……く、訓練ですか？","ENG":"T-training?","TWN":"……訓…訓練嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"따로 훈련을 하지는 않지만, 그냥, 원예를 조금…….","JPN":"特に訓練はしていないですけど、その、園芸を少し……","ENG":"I-I don't train per se, but I do some gardening...","TWN":"我沒做什麼訓練，只有種種花草……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"원예?","JPN":"園芸？","ENG":"Gardening?","TWN":"種花草？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"과연……! 그런 거였군요!","JPN":"なるほど……！　そういうことでしたか！","ENG":"I see...! That's wonderful!","TWN":"果然……！原來如此！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그렇게 커대한 할버드로 꽃들을 다치지 않게끔, 손질하는 세심한 컨트롤 훈련!","JPN":"巨大なハルバードで花を傷つけないよう、丁寧な手入れをすることで繊細なコントロールを訓練されたと……！","ENG":"Using such an enormous halberd for gardening must require extremely fine control!","TWN":"用那麼大的斧槍修剪花草，卻不能傷到花草的力道控制訓練嗎！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"정말로 훌륭한 발상입니다.","JPN":"実にすばらしい発想です。","ENG":"That's a brilliant method of training.","TWN":"真是非常聰明。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"네? 아니, 그건…….","JPN":"え？　いえ、そうじゃ……","ENG":"Sorry? No, that's—","TWN":"呃？不是的，那個……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아카데미 학생들은 누가 가르쳐주지 않아도 스스로 훈련법을 찾아 단련하다니.","JPN":"アカデミー生徒の皆さんは誰かに教えられなくても、自ら訓練法を見つけ出して鍛錬している。","ENG":"These students of the Academy find and practice the best training methods for themselves on their own.","TWN":"學院的學生竟然不需要人家教，就可以自主訓練。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경도 좀 본받았으면 좋겠는데…….","JPN":"リブ卿にも見習ってほしいところです……","ENG":"I wish Dame Liv was like them...","TWN":"真希望莉芙卿也能學一下……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……으음.","JPN":"……うーん。","ENG":"Mm...","TWN":"……嗯嗯。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"한소림 학생?","JPN":"ハネダ・ミズキさん？","ENG":"Han Sorim.","TWN":"韓蕭林同學？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"왜 그러지? 본관의 사격은 완벽했을 텐데?","JPN":"どうした？　本官の射撃は完璧だったはず。","ENG":"What's wrong? My shots were perfect.","TWN":"怎麼了嗎？本官的射擊應該很完美吧？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아쉽게도 제가 총기류에 관해서는 문외한이긴 합니다만…….","JPN":"残念ながら、私は銃器については詳しくありませんが……","ENG":"I'm not knowledgeable in firearms, but…","TWN":"雖然我對槍支類是個門外漢……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"학생은 사격술에 상당한 소질이 있어 보이는군요.","JPN":"そんな私から見ても、相当な腕のように感じます。","ENG":"Even I can tell you're good at shooting.","TWN":"不過我看得出來同學你在射擊方面相當有天份呢。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"당연하지. 이래뵈도 본관은 이 바닥에서는 심판의 방아쇠로 통한다.","JPN":"当たり前だ。こう見えても本官は、審判の引き金と呼ばれている。","ENG":"Of course, I am. In my line of business, I'm better known as the Trigger of Judgment.","TWN":"那當然。本官可是公認的“審判的扳機”呢。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"이 정도 목표물은 식은 죽 먹기지!","JPN":"こんなターゲットに的中させることぐらい朝飯前だ。","ENG":"Target practice like this is nothing!","TWN":"這種程度的目標物對我來說是小菜一碟！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 아쉽게도 군인 치고 체력 점수가 많이 떨어지는 군요.","JPN":"ですが、軍人にしては体力の点数が低いですね。","ENG":"But your physical strength score is noticeably low for soldiers.","TWN":"不過有點可惜，身為軍人，你的體能分數太低。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"……으읏. 그 성적표는 조작된 거다.","JPN":"……ぐう。その成績表は捏造されたものだ。","ENG":"...Hmpf, that score has been forged.","TWN":"……呃呃，那份成績單是偽造的。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"본관의 체력은 그 정도로 떨어지지 않아. 한 사람의 몫은 충분히 해내지.","JPN":"本官の体力はそんなに劣っていない。戦いは一人前にできている。","ENG":"I'm not so weak. At least I can earn my keep.","TWN":"本官的體能沒那麼差，。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……후훗.","JPN":"……フフッ。","ENG":"…Hah hah.","TWN":"……呵呵。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"왜 웃는 거지?","JPN":"なぜ笑う？","ENG":"Why are you laughing?","TWN":"你笑什麼？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"가만보니, 학생은 저희 단원 중에 한 사람을 닮았군요.","JPN":"うちの団員に似ているなと思いまして。","ENG":"You remind me of someone in our knights.","TWN":"仔細一看，同學你很像我們的一個團員呢。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"뭐, 체력이 약한 점을 사격술로 보완하는 것은 나쁜 선택은 아닙니다만.","JPN":"体力が弱いという点を射撃術で補うという戦略は、確かにいい選択です。","ENG":"Well, it's not a bad idea to make up for your weak strength with excellent marksmanship.","TWN":"用射擊數來彌補體能的不足，是個還不錯的選擇。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"쓸모없는 짐을 덜어 군장의 무게를 줄일 필요는 있겠죠.","JPN":"ただ、無駄な荷物を減らして軍装を軽量化する必要はあるでしょう。","ENG":"You can also lighten your burden by removing unnecessary things in your bag.","TWN":"但還是需要減少不必要的行李，以減輕裝備的重量。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그러니까, 이런 건……!!","JPN":"だからこれは……！！","ENG":"For example, like this—","TWN":"所以，像這種東西……！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"……앗! 그, 그건!!","JPN":"……あっ！　そ、それは！！","ENG":"...Ah! Th-that's!","TWN":"……喂！那…那個！！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"그, 그건 만지지 말아주세요. 한정품이란 말이에요!!","JPN":"そ、それだけは触らないでください。限定品なんです！！","ENG":"P-please don't touch that. He's a limited edition!","TWN":"你…不要亂碰啦！那可是限量版欸！！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……서, 설마?","JPN":"……ま、まさか？","ENG":"N-no way...","TWN":"……難…難道是？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"양갈래 머리 학생!!","JPN":"ツインテールさん！！","ENG":"Pigtails!","TWN":"雙馬尾同學！！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"……으, 으응? 무, 무슨 일인데?","JPN":"……え、えっ？　な、何よ？","ENG":"...Wh-what? Wh-what did I do wrong?","TWN":"……呃，蛤？什麼事？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"학생은 설마 그 세 자루의 검을 동시에 다루는 건가요?","JPN":"まさか、3本の剣を同時に使いこなしているのですか？","ENG":"You're not swinging all the three swords at the same time, are you?","TWN":"同學，你是同時控制那三把劍嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그런 검술은 오랫동안 무예에 몸 담은 저조차 한 번도 본 적이 없습니다!","JPN":"そのような剣術は、武芸を長く修めてきた私でさえ見たことがありません！","ENG":"I've been practicing martial arts for a long time, and even I haven't seen anyone do that.","TWN":"就連長期長期投入在武術中的我，都沒看過那種劍術呢！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아까 보였던 자신감은 허세가 아니었군요! 역시 제 눈은 틀리지 않습니다.","JPN":"先ほどの自信満々な態度は伊達じゃなかったのですね。やはり私の目に狂いはありませんでした。","ENG":"What I saw in you earlier wasn't bravado at all. I knew I wasn't wrong about you.","TWN":"看來你剛才不是在虛張聲勢！我的眼光果然沒錯！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"어? 응?","JPN":"えっ？　ん？","ENG":"Huh? Hm?","TWN":"蛤？什麼？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"……어, 뭐, 뭐 그렇지.","JPN":"……あっ、ま、まあそうね。","ENG":"...Err, s-sure, you could say that.","TWN":"……哦，小…小意思啦！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그냥 구닥다리인 줄 알았는데, 나름대로 보는 눈이 있잖아?","JPN":"ただのポンコツだと思ったら、それなりに見る目はあるじゃない。","ENG":"I thought you were just an old country woman, but you have an eye for talent!","TWN":"我還以為你是個土包子呢，沒想到眼光還不錯。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"과연. 성적표를 보니, 학생회장 다음으로 성적이 좋던데.","JPN":"なるほど。成績表を見たところ、生徒会長の次に優秀でしたね。","ENG":"I should have known when I saw your grades were second only to the Student President's.","TWN":"果然沒錯。我看成績單，你的成績僅次於學生會長呢。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그 세 자루의 검을 다루는 검술. 혹시 직접 보여주실 수 있습니까?","JPN":"3本の剣を扱う剣術。拝見させてもらってもいいでしょうか？","ENG":"Mind if you show me how you swing your three swords?","TWN":"你可以親自示範一下，你是怎麼控制那三把劍的嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"에, 에엥? 내, 내가 그걸 왜 보여줘야 하는데!?","JPN":"え、ええっ？　な、なんで私があんたに見せないといけないのよ。","ENG":"Wh-what? Wh-why should I show it to you?","TWN":"什麼？我為什麼要示範給你看！？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그렇군요. 아무리 교관이라고 해도 이건 너무 일방적이고 무례한 부탁이었군요.","JPN":"そうですか……いくら教官とはいえ、さすがにこれは一方的で無礼なお願いでしたね。","ENG":"I'm sorry. Instructor or not, I shouldn't have asked you something so rude.","TWN":"原來如此，就算我是教官，這個要求還是有點太過分嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그래! 잘 알고 있잖아!? 이건 아무에게나 보여줄 수 있는 검술이 아니야!","JPN":"そ、そうよ！　わかってるじゃない。これは誰にでも見せられるような剣術じゃないからね！","ENG":"Th-that's absolutely right! I don't show just anyone my skills!","TWN":"沒…沒錯！你知道就好！我可不會隨隨便便示範的！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"나이엘 님의 실력을 보고 싶다면, 그에 걸맞는 강자를 데려와라, 이 말이지!","JPN":"ナイエル様の腕を確かめたいなら、それに相応しい強者を連れて来なさいっての！","ENG":"If you want to see them, bring me a worthy opponent!","TWN":"要想看奈爾的實力，先找個和我旗鼓相當的高手來再說吧！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……옳습니다. 자고로 무인은 입이 아니라 칼과 창을 맞대어 대화를 나누는 것이 맞죠.","JPN":"……その通りです。武人の会話は口で喋るのはなく、槍と剣をぶつけ合うこと。","ENG":"...I agree. Warriors shouldn't talk. We should communicate through our swords and lances.","TWN":"……說的沒錯。自古以來，習武之人就是用刀槍說話，而不是靠耍嘴皮子。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그렇다면 잠시 교관과 학생의 신분을 내려놓고, 저와 모의 대련을 해보는 건 어떻겠습니까?","JPN":"しばし教官と生徒というのは置いといて、模擬戦をお願いしてもよろしいでしょうか？","ENG":"Let's put aside our roles as instructor and student for now. How'd you like to have a match with me?","TWN":"那就讓我們先暫時放下教官和學生的身分，來比劃一場怎麼樣？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐, 뭐라구!? 모의 대련?? 자, 잠깐만 있어봐, 잠깐!!","JPN":"え、ええ！？　も、模擬戦？　ちょ、ちょっと待って！！","ENG":"Say what? A match? W-wait! Waaait!","TWN":"你…你說什麼！？比劃一場？？等…先等一下，等一下啦！！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L49_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"호오, 선공을 양보하는 건가요? 그렇다면, 사양하지 않겠습니다.","JPN":"ほう、先手を譲るというのですか。なら遠慮はしません。","ENG":"Ooo, are you giving me a chance to attack first? Why, thank you!","TWN":"喔呵！你這是要讓我先出招嗎？那我就恭敬不如從命囉。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"……잠깐만 있어 보라니까아아아!!","JPN":"……ちょっと待ちなさいって！！","ENG":"I said, waaaaaiiiiittt!","TWN":"……等一下啦啦啦！！"},"stage":{"bg":"SKY","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"오늘 하루 수고 많으셨습니다. 피오네 부단장 님.","JPN":"今日は本当にお疲れさまでした、フィオネ副団長。","ENG":"Thank you for everything you've done today, Deputy Lowell.","TWN":"菲奧尼副團長，今天辛苦你了。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아니요. 저야말로 좋은 경험을 했습니다.","JPN":"いえ、こちらこそいい経験になりました。","ENG":"You're welcome. This was a great experience for me, too.","TWN":"別客氣，今天得到很棒的經驗呢！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"늘상 단원들의 훈련만 지도하다가 교단에 서니……","JPN":"いつも団員の訓練指導ばかりでしたが、教壇に立ってみたら……","ENG":"Instructing students in the Academy, instead of my usual training with knights…","TWN":"從單純地訓練團員，到站上講台……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"잊고 있던 마음가짐을 떠올리는 계기가 되었습니다.","JPN":"いつの間に忘れていた大事なことに、再び気づくことができました。","ENG":"I was reminded of an important thing I'd forgotten.","TWN":"這讓有機會我想起我已經遺忘的初心。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"누군가를 가르친다는 것은 동시에 자신도 무언가 배우는 기회라는 것을 말이죠.","JPN":"誰かを教えるということは、自分にとっても学びになるチャンスだということに。","ENG":"By teaching someone, you can learn something from them.","TWN":"有句話說，教別人的同時，其實學到的是自己。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네, 좋은 말씀입니다. 저도 늘 잊지 않으려고 노력하죠.","JPN":"素敵なお言葉ですね。私もそのことを忘れないように日々努力しているんですよ。","ENG":"I agree. I try not to forget that, either.","TWN":"沒錯，我也常常努力不忘記初心。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"맞습니다.","JPN":"そうですね。","ENG":"Yes.","TWN":"沒錯。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"참고로 저희 부친께서 훈련 교관을 맡았던 시절에는…….","JPN":"ちなみに、父が訓練の教官を勤めていた頃は……","ENG":"Speaking of which, when my father was a training instructor...","TWN":"提供你參考，我的父親在擔任訓練教官時……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"……아무래도 오늘 내로 가시진 않을 것 같군요.","JPN":"……どうやら、今日中に帰る気はないようですね。","ENG":"...You're not going to leave anytime soon, are you?","TWN":"……看來今天很可能會徹夜長談。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};